  1→import { Injectable, BadRequestException, Logger } from '@nestjs/common';
  2→import { ConfigService } from '@nestjs/config';
  3→import Stripe from 'stripe';
  4→import { PrismaService } from '../prisma/prisma.service';
  5→import type { PlanType } from '@agent-analytics/types';
  6→
  7→@Injectable()
  8→export class BillingService {
  9→  private readonly stripe: Stripe;
 10→  private readonly logger = new Logger(BillingService.name);
 11→  private readonly priceToplan: Record<string, PlanType>;
 12→  private readonly planToPrice: Record<string, string>;
 13→
 14→  constructor(
 15→    private readonly prisma: PrismaService,
 16→    private readonly configService: ConfigService,
 17→  ) {
 18→    this.stripe = new Stripe(
 19→      this.configService.getOrThrow<string>('STRIPE_SECRET_KEY'),
 20→    );
 21→
 22→    const starterPrice = this.configService.getOrThrow<string>('STRIPE_PRICE_STARTER');
 23→    const proPrice = this.configService.getOrThrow<string>('STRIPE_PRICE_PRO');
 24→    const businessPrice = this.configService.getOrThrow<string>('STRIPE_PRICE_BUSINESS');
 25→
 26→    this.priceToplan = {
 27→      [starterPrice]: 'starter',
 28→      [proPrice]: 'pro',
 29→      [businessPrice]: 'business',
 30→    };
 31→
 32→    this.planToPrice = {
 33→      starter: starterPrice,
 34→      pro: proPrice,
 35→      business: businessPrice,
 36→    };
 37→  }
 38→
 39→  async createCheckoutSession(
 40→    userId: string,
 41→    plan: Exclude<PlanType, 'free'>,
 42→  ): Promise<string> {
 43→    const user = await this.prisma.user.findUniqueOrThrow({
 44→      where: { id: userId },
 45→    });
 46→
 47→    // Get or create Stripe customer
 48→    let customerId = user.stripeCustomerId;
 49→    if (!customerId) {
 50→      const customer = await this.stripe.customers.create({
 51→        email: user.email,
 52→        metadata: { userId },
 53→      });
 54→      customerId = customer.id;
 55→      await this.prisma.user.update({
 56→        where: { id: userId },
 57→        data: { stripeCustomerId: customerId },
 58→      });
 59→    }
 60→
 61→    const priceId = this.planToPrice[plan];
 62→    if (!priceId) {
 63→      throw new BadRequestException(`Invalid plan: ${plan}`);
 64→    }
 65→
 66→    const appUrl = this.configService.getOrThrow<string>('APP_URL');
 67→
 68→    const session = await this.stripe.checkout.sessions.create({
 69→      customer: customerId,
 70→      mode: 'subscription',
 71→      line_items: [{ price: priceId, quantity: 1 }],
 72→      success_url: `${appUrl}/billing?success=true`,
 73→      cancel_url: `${appUrl}/billing?canceled=true`,
 74→      metadata: { userId, plan },
 75→    });
 76→
 77→    return session.url ?? '';
 78→  }
 79→
 80→  async handleWebhook(rawBody: Buffer, signature: string): Promise<void> {
 81→    const webhookSecret = this.configService.getOrThrow<string>(
 82→      'STRIPE_WEBHOOK_SECRET',
 83→    );
 84→
 85→    let event: Stripe.Event;
 86→    try {
 87→      event = this.stripe.webhooks.constructEvent(
 88→        rawBody,
 89→        signature,
 90→        webhookSecret,
 91→      );
 92→    } catch (err) {
 93→      this.logger.error('Webhook signature verification failed', err);
 94→      throw new BadRequestException('Invalid webhook signature');
 95→    }
 96→
 97→    switch (event.type) {
 98→      case 'customer.subscription.updated':
 99→      case 'customer.subscription.created':
100→        await this.handleSubscriptionUpdated(
101→          event.data.object as Stripe.Subscription,
102→        );
103→        break;
104→      case 'customer.subscription.deleted':
105→        await this.handleSubscriptionDeleted(
106→          event.data.object as Stripe.Subscription,
107→        );
108→        break;
109→      default:
110→        this.logger.log(`Unhandled event type: ${event.type}`);
111→    }
112→  }
113→
114→  private async handleSubscriptionUpdated(
115→    subscription: Stripe.Subscription,
116→  ): Promise<void> {
117→    const customerId = subscription.customer as string;
118→    const priceId = subscription.items.data[0]?.price.id;
119→
120→    if (!priceId) {
121→      this.logger.warn('No price found on subscription');
122→      return;
123→    }
124→
125→    const plan: PlanType = this.priceToplan[priceId] ?? 'free';
126→
127→    await this.prisma.$transaction(async (tx) => {
128→      const user = await tx.user.findUnique({
129→        where: { stripeCustomerId: customerId },
130→      });
131→      if (!user) {
132→        this.logger.warn(`No user for Stripe customer ${customerId}`);
133→        return;
134→      }
135→
136→      await tx.user.update({
137→        where: { id: user.id },
138→        data: {
139→          stripeSubscriptionId: subscription.id,
140→          stripePriceId: priceId,
141→        },
142→      });
143→
144→      // Update all user's sites plan (denormalized)
145→      await tx.site.updateMany({
146→        where: { userId: user.id },
147→        data: { plan },
148→      });
149→    });
150→  }
151→
152→  private async handleSubscriptionDeleted(
153→    subscription: Stripe.Subscription,
154→  ): Promise<void> {
155→    const customerId = subscription.customer as string;
156→
157→    await this.prisma.$transaction(async (tx) => {
158→      const user = await tx.user.findUnique({
159→        where: { stripeCustomerId: customerId },
160→      });
161→      if (!user) return;
162→
163→      await tx.user.update({
164→        where: { id: user.id },
165→        data: {
166→          stripeSubscriptionId: null,
167→          stripePriceId: null,
168→        },
169→      });
170→
171→      // Reset all sites to free
172→      await tx.site.updateMany({
173→        where: { userId: user.id },
174→        data: { plan: 'free' },
175→      });
176→    });
177→  }
178→
179→  async getBillingPortalUrl(userId: string): Promise<string> {
180→    const user = await this.prisma.user.findUniqueOrThrow({
181→      where: { id: userId },
182→    });
183→
184→    if (!user.stripeCustomerId) {
185→      throw new BadRequestException('No billing account found');
186→    }
187→
188→    const appUrl = this.configService.getOrThrow<string>('APP_URL');
189→
190→    const session = await this.stripe.billingPortal.sessions.create({
191→      customer: user.stripeCustomerId,
192→      return_url: `${appUrl}/billing`,
193→    });
194→
195→    return session.url;
196→  }
197→}
