  1→import { Injectable, Logger } from '@nestjs/common';
  2→import { InjectQueue } from '@nestjs/bullmq';
  3→import { Queue } from 'bullmq';
  4→import { AgentDetectionService } from '../agent-detection/agent-detection.service';
  5→import { CollectEventDto } from './dto/collect-event.dto';
  6→import {
  7→  getAgentType,
  8→  AI_REFERRAL_DOMAINS,
  9→  type AgentType,
 10→} from '@agent-analytics/types';
 11→
 12→interface RequestContext {
 13→  userAgent: string;
 14→  referer?: string;
 15→  accept?: string;
 16→  ip?: string;
 17→}
 18→
 19→type ReferrerType = 'ai_referral' | 'organic' | 'direct' | 'other';
 20→
 21→interface ReferrerInfo {
 22→  referrerDomain: string | null;
 23→  referrerType: ReferrerType;
 24→  aiReferralSource: string | null;
 25→}
 26→
 27→@Injectable()
 28→export class IngestService {
 29→  private readonly logger = new Logger(IngestService.name);
 30→
 31→  constructor(
 32→    @InjectQueue('events') private readonly eventsQueue: Queue,
 33→    private readonly agentDetection: AgentDetectionService,
 34→  ) {}
 35→
 36→  async enqueue(dto: CollectEventDto, ctx: RequestContext): Promise<void> {
 37→    // Enrich with server-side agent detection
 38→    const serverDetection = this.agentDetection.detect(ctx, dto.agent);
 39→
 40→    // Classify agent type
 41→    const agentType: AgentType | null = serverDetection.isAgent
 42→      ? getAgentType(serverDetection.agentName)
 43→      : null;
 44→
 45→    // Parse referrer info from request context + client meta
 46→    const referrerInfo = this.parseReferrer(ctx.referer, dto.meta);
 47→
 48→    const enrichedEvent = {
 49→      ...dto,
 50→      serverAgent: {
 51→        isAgent: serverDetection.isAgent,
 52→        agentName: serverDetection.agentName,
 53→        confidence: serverDetection.confidence,
 54→      },
 55→      agentType,
 56→      referrerDomain: referrerInfo.referrerDomain,
 57→      referrerType: referrerInfo.referrerType,
 58→      requestContext: {
 59→        ip: ctx.ip,
 60→        userAgent: ctx.userAgent,
 61→      },
 62→    };
 63→
 64→    // Merge AI referral source into meta if detected
 65→    if (referrerInfo.aiReferralSource) {
 66→      enrichedEvent.meta = {
 67→        ...enrichedEvent.meta,
 68→        aiReferral: true,
 69→        aiReferralSource: referrerInfo.aiReferralSource,
 70→      };
 71→    }
 72→
 73→    await this.eventsQueue.add('process', enrichedEvent, {
 74→      removeOnComplete: true,
 75→      removeOnFail: false,
 76→      attempts: 3,
 77→      backoff: { type: 'exponential', delay: 2000 },
 78→    });
 79→
 80→    this.logger.debug(`Event enqueued for site ${dto.siteId}`);
 81→  }
 82→
 83→  private parseReferrer(
 84→    serverReferer: string | undefined,
 85→    clientMeta: Record<string, unknown> | undefined,
 86→  ): ReferrerInfo {
 87→    // Client-side tracker may send AI referral info in meta
 88→    const clientAiReferral = clientMeta?.aiReferral === true;
 89→    const clientAiSource = clientMeta?.aiReferralSource as string | undefined;
 90→
 91→    if (clientAiReferral && clientAiSource) {
 92→      const domain = this.findAiDomainBySource(clientAiSource);
 93→      return {
 94→        referrerDomain: domain,
 95→        referrerType: 'ai_referral',
 96→        aiReferralSource: clientAiSource,
 97→      };
 98→    }
 99→
100→    // Server-side: parse Referer header
101→    if (!serverReferer) {
102→      return { referrerDomain: null, referrerType: 'direct', aiReferralSource: null };
103→    }
104→
105→    try {
106→      const url = new URL(serverReferer);
107→      const domain = url.hostname.replace(/^www\./, '');
108→      const aiSource = AI_REFERRAL_DOMAINS[domain];
109→
110→      if (aiSource) {
111→        return {
112→          referrerDomain: domain,
113→          referrerType: 'ai_referral',
