  7→import { PLAN_LIMITS, type PlanType } from '@agent-analytics/types';
  8→
  9→interface ProcessEventPayload {
 10→  siteId: string;
 11→  url: string;
 12→  action: string;
 13→  timestamp: number;
 14→  source?: 'tracker' | 'server';
 15→  meta?: Record<string, unknown>;
 16→  serverAgent: {
 17→    isAgent: boolean;
 18→    agentName: string;
 19→    confidence: number;
 20→  };
 21→  agentType?: string | null;
 22→  referrerDomain?: string | null;
 23→  referrerType?: string | null;
 24→  requestContext: {
 25→    ip?: string;
 26→    userAgent: string;
 27→  };
 28→}
