 30→@Processor('events')
 31→export class EventProcessor extends WorkerHost {
 32→  private readonly logger = new Logger(EventProcessor.name);
 33→
 34→  constructor(
 35→    private readonly prisma: PrismaService,
 36→    private readonly redis: RedisService,
 37→  ) {
 38→    super();
 39→  }
 40→
 41→  async process(job: Job<ProcessEventPayload>): Promise<void> {
 42→    const data = job.data;
 43→
 44→    // 1. Validate site exists & check plan limits (siteId from client = apiKey)
 45→    const site = await this.prisma.site.findUnique({
 46→      where: { apiKey: data.siteId },
 47→      select: { id: true, plan: true },
 48→    });
 49→
 50→    if (!site) {
 51→      this.logger.warn(`Site not found for apiKey: ${data.siteId}`);
 52→      return;
 53→    }
 54→
 55→    // 2. Check monthly usage limit
 56→    const withinLimit = await this.checkMonthlyLimit(site.id, site.plan as PlanType);
 57→    if (!withinLimit) {
 58→      this.logger.warn(`Site ${site.id} exceeded monthly event limit`);
 59→      return;
 60→    }
 61→
 62→    // 3. Deduplicate (Redis SET with TTL 1s)
 63→    const dedupeKey = `dedup:${site.id}:${data.url}:${data.timestamp}`;
 64→    const isNew = await this.redis.set(dedupeKey, '1', 'EX', 1, 'NX');
 65→    if (!isNew) {
 66→      return;
 67→    }
 68→
 69→    // 4. Insert event into PostgreSQL
 70→    await this.prisma.event.create({
 71→      data: {
 72→        siteId: site.id,
 73→        url: data.url,
 74→        action: data.action,
 75→        isAgent: data.serverAgent.isAgent,
 76→        agentName: data.serverAgent.isAgent ? data.serverAgent.agentName : null,
 77→        agentType: data.agentType ?? null,
 78→        confidence: data.serverAgent.confidence,
 79→        source: data.source ?? null,
 80→        referrerDomain: data.referrerDomain ?? null,
 81→        referrerType: data.referrerType ?? null,
 82→        timestamp: new Date(data.timestamp),
 83→        meta: (data.meta as Prisma.InputJsonValue) ?? undefined,
 84→      },
 85→    });
 86→
 87→    // 5. Increment monthly usage
 88→    await this.incrementMonthlyUsage(site.id);
 89→
 90→    // 6. Invalidate analytics cache for this site
 91→    await this.invalidateCache(site.id);
 92→
 93→    this.logger.debug(`Event processed for site ${site.id}`);
 94→  }
 95→
 96→  private async checkMonthlyLimit(siteId: string, plan: PlanType): Promise<boolean> {
 97→    const limit = PLAN_LIMITS[plan].eventsPerMonth;
 98→    if (limit === Infinity) return true;
 99→
100→    const now = new Date();
101→    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
102→
103→    const usage = await this.prisma.monthlyUsage.findUnique({
104→      where: { siteId_month: { siteId, month: monthStart } },
105→    });
106→
107→    return !usage || usage.eventCount < limit;
108→  }
109→
110→  private async incrementMonthlyUsage(siteId: string): Promise<void> {
111→    const now = new Date();
112→    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
113→
114→    await this.prisma.monthlyUsage.upsert({
115→      where: { siteId_month: { siteId, month: monthStart } },
116→      update: { eventCount: { increment: 1 } },
117→      create: { siteId, month: monthStart, eventCount: 1 },
118→    });
119→  }
120→
121→  private async invalidateCache(siteId: string): Promise<void> {
122→    const keys = await this.redis.keys(`overview:${siteId}:*`);
123→    if (keys.length > 0) {
124→      await this.redis.del(...keys);
125→    }
126→  }
127→}
